// ============================================================================
// miles-slack-actions-router · Parse & Classify Action
// ----------------------------------------------------------------------------
// Router (dispatcher) de la Interactivity API de Slack. Endpoint: /slack-actions
// (configurado como Interactivity Request URL del Slack App de Miles).
//
// A diferencia de la Events API, Slack envia las interacciones como
// application/x-www-form-urlencoded con un campo `payload` que es un JSON
// stringificado. Hay que JSON.parse(decodeURIComponent(payload)) para leerlo.
//
// RESPONSABILIDAD UNICA: leer el discriminador y rutear. NO procesa negocio.
// El payload crudo se reenvia tal cual al handler que corresponda (passthrough),
// para que el parseo existente de cada handler siga funcionando sin cambios.
//
// Discriminadores soportados:
//   callback_id.startsWith('req_approval')  -> 'approval'  (formato legacy attachments)
//   (todo lo demas)                         -> 'unknown'   -> noOp
//
// A medida que Miles sume interacciones (modales, otros botones), se agregan
// ramas nuevas aca + en el Switch, sin tocar los handlers existentes.
// ============================================================================

const body = $json.body || {};

// El payload puede venir como string (form field `payload`) o ya como objeto.
const raw = body.payload || body || '';
let payload;
try {
  payload = typeof raw === 'string' ? JSON.parse(decodeURIComponent(raw)) : raw;
} catch (e) {
  // Si no parsea, no rompemos: clasificamos como unknown y dejamos traza.
  return [{ json: { action_type: 'unknown', _reason: 'parse_error', _raw: String(raw).slice(0, 500) } }];
}

const payloadType = payload.type || '';                 // 'interactive_message' (legacy) | 'block_actions' | 'view_submission' ...
const callbackId  = payload.callback_id || '';          // legacy attachments
const actionId    = (payload.actions && payload.actions[0] && payload.actions[0].action_id) || ''; // block kit moderno

// --- Clasificacion ----------------------------------------------------------
// Aprobacion de REQ: callback_id `req_approval_*` (legacy). Tambien contemplamos
// un eventual action_id `req_approval*` por si se migra a Block Kit en el futuro.
const isApproval = callbackId.startsWith('req_approval') || actionId.startsWith('req_approval');

if (isApproval) {
  // Passthrough: reenviamos el payload CRUDO (string original) para que el
  // approval-handler lo parsee como siempre. Si vino como string lo mandamos
  // tal cual; si vino objeto, lo re-stringificamos.
  const rawPayloadString = typeof raw === 'string' ? raw : JSON.stringify(raw);
  return [{ json: {
    action_type: 'approval',
    raw_payload: rawPayloadString,
    callback_id: callbackId,
  }}];
}

// --- Sin match -> unknown (noOp). No hacemos nada, pero dejamos traza. -------
return [{ json: {
  action_type: 'unknown',
  _reason: 'no_match',
  payload_type: payloadType,
  callback_id: callbackId,
  action_id: actionId,
}}];
